diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..66ae10b2c55d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1135,6 +1135,51 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
   return nullptr;
 }

+/// Fold (X != -1) & ((X + 1) u<= Y) --> X u< Y
+/// This is valid because:
+/// - If X = -1 (all ones), then (X != -1) is false, so the result is false.
+///   Also, X u< Y is false when X is the maximum value.
+/// - If X != -1, then (X + 1) doesn't wrap, and (X + 1) u<= Y is equivalent to X u< Y.
+static Value *foldICmpNeAllOnesAndICmpUleAddOne(ICmpInst *NeICmp, ICmpInst *UleICmp,
+                                                InstCombiner::BuilderTy &Builder) {
+  // Check if NeICmp is (X != -1)
+  ICmpInst::Predicate NePred = NeICmp->getPredicate();
+  if (NePred != ICmpInst::ICMP_NE)
+    return nullptr;
+  
+  Value *NeOp0 = NeICmp->getOperand(0);
+  Value *NeOp1 = NeICmp->getOperand(1);
+  const APInt *NeConst;
+  if (!match(NeOp1, m_APInt(NeConst)) || !NeConst->isAllOnes())
+    return nullptr;
+  
+  // Check if UleICmp is ((X + 1) u<= Y)
+  ICmpInst::Predicate UlePred = UleICmp->getPredicate();
+  if (UlePred != ICmpInst::ICMP_ULE)
+    return nullptr;
+  
+  Value *UleOp0 = UleICmp->getOperand(0);
+  Value *UleOp1 = UleICmp->getOperand(1);
+  
+  // Check if UleOp0 is (X + 1)
+  Value *AddX, *AddC;
+  const APInt *AddConst;
+  if (!match(UleOp0, m_Add(m_Value(AddX), m_APInt(AddConst))))
+    return nullptr;
+  
+  // Check if AddX is the same as NeOp0 (the X in X != -1)
+  if (AddX != NeOp0)
+    return nullptr;
+  
+  // Check if the constant is 1
+  if (!AddConst->isOne())
+    return nullptr;
+  
+  // Pattern matched: (X != -1) & ((X + 1) u<= Y) --> X u< Y
+  return Builder.CreateICmpULT(NeOp0, UleOp1);
+}
+
+
 struct IntPart {
   Value *From;
   unsigned StartBit;
@@ -3105,6 +3150,13 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return X;
     if (Value *X = foldUnsignedUnderflowCheck(RHS, LHS, IsAnd, Q, Builder))
       return X;
+    // (X != -1) & ((X + 1) u<= Y) --> X u< Y
+    if (IsAnd) {
+      if (Value *X = foldICmpNeAllOnesAndICmpUleAddOne(LHS, RHS, Builder))
+        return X;
+      if (Value *X = foldICmpNeAllOnesAndICmpUleAddOne(RHS, LHS, Builder))
+        return X;
+    }
   }

   if (Value *X = foldEqOfParts(LHS, RHS, IsAnd))

